import React, { useState } from 'react';
import './App.css';
import Header from './components/Header';
import GeneratorForm from './components/GeneratorForm';
import NftPreview from './components/NftPreview';
import Footer from './components/Footer';

function App() {
  const [inputText, setInputText] = useState('');
  const [submitted, setSubmitted] = useState(false);

  // Handle the generation of NFT images
  const handleGenerate = (description, style) => {
    console.log(description, style);
    setPreviewImage('https://via.placeholder.com/600x400'); // Placeholder for generated image
  };
  
  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true); // Mark as submitted
    // Handle your form submission logic (e.g., sending data)
  };

  return (
    <div className="App">
      <form onSubmit={handleSubmit}></form>
      <Header />
      <div className="main-content">
        <input
          type="text"
          className={`form-input ${submitted ? 'submitted' : ''}`}
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          placeholder="Describe your image..."
        />
        <GeneratorForm onGenerate={handleGenerate} />
        {previewImage && <NftPreview previewImage={previewImage} />}
      </div>
      <Footer />
    </div>
  );
}

export default App;
